                        <div class="xyt-meter-track"><div class="xyt-meter-fill" style="width:${favor}%"></div></div>
                    </div>
                </div>
            </summary>
            <div class="xyt-card-body">
                <div class="xyt-detail"><span class="xyt-detail-icon">👗</span><span class="xyt-detail-key">穿着</span><span class="xyt-detail-val">${esc(dress.trim())}</span></div>
                <div class="xyt-detail"><span class="xyt-detail-icon">💃</span><span class="xyt-detail-key">身材</span><span class="xyt-detail-val">${esc(body.trim())}</span></div>
                <div class="xyt-detail"><span class="xyt-detail-icon">💭</span><span class="xyt-detail-key">内心</span><span class="xyt-detail-val">${esc(thought.trim())}</span></div>
            </div>
        </details>`;
    }
    if(fHtml && fContainer){
        fContainer.innerHTML = fHtml;
        if(fLabel) fLabel.style.display = 'flex';
    }

    /* ---- 解析男性NPC ---- */
    const mContainer = document.getElementById('xyt-cards-m');
    const mLabel     = document.getElementById('xyt-label-m');
    const regM = /\[角色\|(.*?)\|(.*?)\|(.*?)\|(.*?)\]/g;
    let mm, mHtml = '';
    while((mm = regM.exec(mText)) !== null){
        let [,name,role,thought,cuck] = mm;
        cuck=clamp(cuck);
        mHtml += `
        <details class="xyt-card">
            <summary class="xyt-card-head">
                <div class="xyt-card-identity">
                    <span class="xyt-card-name" style="color:var(--xyt-teal);">♂ ${esc(name.trim())} <span class="xyt-arrow-sm">▼</span></span>
                    <span class="xyt-card-spouse">🏷️ ${esc(role.trim())}</span>
                </div>
                <div class="xyt-meters">
                    <div class="xyt-meter xyt-meter-cuck">
                        <span class="xyt-meter-label">🤢 绿帽 ${cuck}</span>
                        <div class="xyt-meter-track"><div class="xyt-meter-fill" style="width:${cuck}%"></div></div>
                    </div>
                </div>
            </summary>
            <div class="xyt-card-body">
                <div class="xyt-detail"><span class="xyt-detail-icon">💭</span><span class="xyt-detail-key">内心</span><span class="xyt-detail-val">${esc(thought.trim())}</span></div>
            </div>
        </details>`;
    }
    if(mHtml && mContainer){
        mContainer.innerHTML = mHtml;
        if(mLabel) mLabel.style.display = 'flex';
    }

    /* ---- 空状态 ---- */
    if(!fHtml && !mHtml){
        const emptyEl = document.getElementById('xyt-empty');
        if(emptyEl) emptyEl.style.display = 'block';
    }

    /* ---- 清理原始数据节点 ---- */
    if(rawEnv) rawEnv.remove();
    if(rawF) rawF.remove();
    if(rawM) rawM.remove();
})();
