            +'<div class="xyt-mr"><span class="xyt-ml xyt-ml-f">💜好感 '+fv+'</span><div class="xyt-trk"><div class="xyt-fl xyt-fl-f" style="width:'+fv+'%"></div></div></div>'
            +'</div>'
            +'</summary>'
